// Phase 5: TypeChecker - 정적 타입 검증

import { Expr, Stmt, Program } from "./ast"
import {
  Type,
  PrimitiveType,
  TypeCheckError,
  TypeCheckResult,
  typesCompatible,
  typeToString,
  getOperationResultType,
  inferTypeFromValue,
  BUILTIN_TYPES,
} from "./type-system"

/**
 * TypeChecker: AST 기반 정적 타입 검증
 */
export class TypeChecker {
  private env: Map<string, Type> = new Map()
  private functionTypes: Map<string, Type> = new Map()
  private errors: TypeCheckError[] = []
  private lineCount = 0

  /**
   * 전체 프로그램 타입 검사
   */
  public check(program: Program): TypeCheckResult {
    this.errors = []
    this.env.clear()
    this.functionTypes.clear()

    // First pass: 함수 정의 수집
    for (const stmt of program.statements) {
      if (stmt.type === "fn") {
        this.registerFunctionType(stmt)
      }
    }

    // Second pass: 함수 본문 및 다른 명령문 검사
    for (const stmt of program.statements) {
      this.checkStmt(stmt)
    }

    return {
      success: this.errors.length === 0,
      errors: this.errors,
      types: new Map(this.env),
    }
  }

  /**
   * 함수 타입 등록
   */
  private registerFunctionType(stmt: any): void {
    if (stmt.type === "fn") {
      const paramTypes: Type[] = stmt.params.map(() => ({
        kind: "primitive" as const,
        type: PrimitiveType.UNKNOWN,
      }))

      const returnType: Type = {
        kind: "primitive",
        type: PrimitiveType.UNKNOWN,
      }

      const fnType: Type = {
        kind: "fn",
        paramTypes,
        returnType,
      }

      this.functionTypes.set(stmt.name, fnType)
    }
  }

  /**
   * 명령문 타입 검사
   */
  private checkStmt(stmt: Stmt): void {
    switch (stmt.type) {
      case "print":
        this.checkExpr(stmt.expr)
        break

      case "expr":
        this.checkExpr(stmt.expr)
        break

      case "fn":
        // 함수 본문 검사
        const savedEnv = new Map(this.env)
        const fn = stmt as any
        for (const param of fn.params) {
          this.env.set(param.name, {
            kind: "primitive",
            type: PrimitiveType.UNKNOWN,
          })
        }
        for (const s of fn.body) {
          this.checkStmt(s)
        }
        this.env = savedEnv
        break

      case "if":
        const ifStmt = stmt as any
        this.checkExpr(ifStmt.condition)
        for (const s of ifStmt.then) {
          this.checkStmt(s)
        }
        if (ifStmt.else) {
          for (const s of ifStmt.else) {
            this.checkStmt(s)
          }
        }
        break

      case "for":
        const forStmt = stmt as any
        this.checkExpr(forStmt.iter)
        for (const s of forStmt.body) {
          this.checkStmt(s)
        }
        break

      case "return":
        const returnStmt = stmt as any
        if (returnStmt.value) {
          this.checkExpr(returnStmt.value)
        }
        break
    }
  }

  /**
   * 표현식 타입 검사
   */
  public checkExpr(expr: Expr): Type {
    switch (expr.type) {
      case "num":
        return { kind: "primitive", type: PrimitiveType.NUM }

      case "str":
        return { kind: "primitive", type: PrimitiveType.STR }

      case "bool":
        return { kind: "primitive", type: PrimitiveType.BOOL }

      case "null":
        return { kind: "primitive", type: PrimitiveType.NULL }

      case "var": {
        const varExpr = expr as any
        const type = this.env.get(varExpr.name)
        if (!type) {
          this.addError(
            `Undefined variable '${varExpr.name}'`,
            expr.line,
            expr.column
          )
          return BUILTIN_TYPES.UNKNOWN
        }
        return type
      }

      case "assign": {
        const assignExpr = expr as any
        const valueType = this.checkExpr(assignExpr.value)
        this.env.set(assignExpr.name, valueType)
        return valueType
      }

      case "binary": {
        const binExpr = expr as any
        const leftType = this.checkExpr(binExpr.left)
        const rightType = this.checkExpr(binExpr.right)

        // 타입 호환성 검사
        const resultType = getOperationResultType(
          binExpr.op,
          leftType,
          rightType
        )

        // 검증 로직
        if (binExpr.op === "Add") {
          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
            const left = leftType.type
            const right = rightType.type

            // 타입 가능성 확인
            if (
              !(
                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
                (left === PrimitiveType.STR ||
                  right === PrimitiveType.STR) ||
                (left === PrimitiveType.UNKNOWN ||
                  right === PrimitiveType.UNKNOWN)
              )
            ) {
              this.addError(
                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
                expr.line,
                expr.column,
                binExpr.name,
                leftType,
                rightType
              )
            }
          }
        }

        return resultType
      }

      case "unary": {
        const unaryExpr = expr as any
        const operandType = this.checkExpr(unaryExpr.operand)

        if (unaryExpr.op === "Not") {
          if (operandType.kind !== "primitive" || operandType.type !== PrimitiveType.BOOL) {
            this.addError(
              `Cannot apply Not to ${typeToString(operandType)}`,
              expr.line,
              expr.column
            )
          }
          return BUILTIN_TYPES.BOOL
        }

        if (unaryExpr.op === "Neg") {
          if (operandType.kind !== "primitive" || operandType.type !== PrimitiveType.NUM) {
            this.addError(
              `Cannot negate ${typeToString(operandType)}`,
              expr.line,
              expr.column
            )
          }
          return BUILTIN_TYPES.NUM
        }

        return operandType
      }

      case "call": {
        const callExpr = expr as any
        const fnType = this.functionTypes.get(callExpr.fn)

        if (!fnType) {
          this.addError(
            `Undefined function '${callExpr.fn}'`,
            expr.line,
            expr.column
          )
          return BUILTIN_TYPES.UNKNOWN
        }

        if (fnType.kind === "fn") {
          // 인자 개수 확인
          if (callExpr.args.length !== fnType.paramTypes.length) {
            this.addError(
              `Function '${callExpr.fn}' expects ${fnType.paramTypes.length} arguments, got ${callExpr.args.length}`,
              expr.line,
              expr.column
            )
          }

          // 인자 타입 검사
          for (let i = 0; i < callExpr.args.length; i++) {
            const argType = this.checkExpr(callExpr.args[i])
            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN

            if (!typesCompatible(argType, paramType)) {
              this.addError(
                `Argument ${i} of '${callExpr.fn}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
                expr.line,
                expr.column,
                undefined,
                paramType,
                argType
              )
            }
          }

          return fnType.returnType
        }

        return BUILTIN_TYPES.UNKNOWN
      }

      case "array": {
        const arrayExpr = expr as any
        if (arrayExpr.elements.length === 0) {
          return {
            kind: "array",
            elementType: BUILTIN_TYPES.UNKNOWN,
          }
        }

        const elementTypes = arrayExpr.elements.map((e: any) => this.checkExpr(e))

        // 모든 요소 타입이 같은지 확인
        const firstType = elementTypes[0]
        for (let i = 1; i < elementTypes.length; i++) {
          if (!typesCompatible(elementTypes[i], firstType)) {
            this.addError(
              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
              expr.line,
              expr.column
            )
          }
        }

        return {
          kind: "array",
          elementType: firstType,
        }
      }

      case "index": {
        const indexExpr = expr as any
        const arrayType = this.checkExpr(indexExpr.array)
        const indexType = this.checkExpr(indexExpr.index)

        // 배열 타입 확인
        if (arrayType.kind !== "array") {
          this.addError(
            `Cannot index non-array type ${typeToString(arrayType)}`,
            expr.line,
            expr.column
          )
          return BUILTIN_TYPES.UNKNOWN
        }

        // 인덱스 타입 확인
        if (indexType.kind !== "primitive" || indexType.type !== PrimitiveType.NUM) {
          this.addError(
            `Array index must be number, got ${typeToString(indexType)}`,
            expr.line,
            expr.column
          )
        }

        return arrayType.elementType
      }

      default:
        return BUILTIN_TYPES.UNKNOWN
    }
  }

  /**
   * 오류 추가
   */
  private addError(
    message: string,
    line?: number,
    column?: number,
    variable?: string,
    expected?: Type,
    actual?: Type
  ): void {
    this.errors.push({
      message,
      line,
      column,
      variable,
      expected,
      actual,
    })
  }

  /**
   * 환경 조회
   */
  public getEnv(): Map<string, Type> {
    return new Map(this.env)
  }

  /**
   * 함수 타입 조회
   */
  public getFunctionType(name: string): Type | undefined {
    return this.functionTypes.get(name)
  }

  /**
   * 오류 개수
   */
  public getErrorCount(): number {
    return this.errors.length
  }

  /**
   * 오류 목록
   */
  public getErrors(): TypeCheckError[] {
    return [...this.errors]
  }
}
